import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        List<String> todo = new ArrayList<>();
        todo.add("Brush teeth");
        todo.add("Do homwork");
        todo.add("Feed cat");

        todo.set(1, "Do homework");
        todo.remove("Brush teeth");

        System.out.println("Things left to do:");
        for (String task : todo) {
            System.out.println("- " + task);
        }
        System.out.println("Is 'Feed cat' on the list? " + todo.contains("Feed cat"));
    }
}

import java.util.ArrayList;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        List<Integer> scores = new ArrayList<>();
        scores.add(90);
        scores.add(75);
        scores.add(100);

        int total = 0;
        for (int s : scores) {
            total = total + s;
        }
        System.out.println("Number of scores: " + scores.size());
        System.out.println("Total: " + total);
        System.out.println("Average: " + (total / scores.size()));
    }
}

